// Grant entitlements from the resolved policy (batch upsert to PostgREST).
const p = $('Gen Correlation + Normalize').first().json;
const pol = $('Resolve Policy').first().json;
const ents = (pol.policy && pol.policy.entitlements) || {};
const H = { apikey: p.service_key, Authorization: 'Bearer ' + p.service_key, 'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates,return=representation' };
const rows = Object.keys(ents).map(function (feature) {
  return { tenant_id: p.tenant_id, feature: feature, enabled: !!ents[feature] };
});
let result = [];
if (rows.length > 0) {
  result = await this.helpers.httpRequest({
    method: 'POST',
    url: p.supabase_url + '/rest/v1/entitlements?on_conflict=tenant_id,feature',
    headers: H,
    body: rows,
    json: true
  });
}
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, entitlements: ents, granted: rows.length } }];

const p = $('Gen Correlation + Normalize').first().json;
