const p = $('Gen Correlation + Normalize').first().json;
const pol = $('Resolve Policy').first().json;
const approval = (pol.policy && pol.policy.approval) || {};
const text = [
  'Onboarding approval needed',
  'Tenant: ' + (pol.tenant_name || p.tenant_id) + ' (' + (pol.plan || 'unknown') + ')',
  'Amount: $' + (p.amount_usd || 0),
  'Approver: ' + (approval.approver || 'n/a'),
  'Correlation: `' + p.correlation_id + '`'
].join('\n');
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: 'onboarding',
  step: 'approval',
  text,
  parse_mode: 'Markdown',
  timeout_hours: 24,
  approver: approval.approver || null,
  second_approver: approval.second_approver || null,
  payload: {
    tenant_name: pol.tenant_name,
    plan: pol.plan,
    amount_usd: p.amount_usd,
    approver: approval.approver || null,
    second_approver: approval.second_approver || null
  }
} }];
